import{c as a,Q as n,j as s,m as e}from"./chunks/framework.ga0D1uIo.js";const b=JSON.parse('{"title":"第二十三章：大语言模型原理","description":"","frontmatter":{},"headers":[],"relativePath":"modern-nlp/llm.md","filePath":"modern-nlp/llm.md","lastUpdated":1779795405000}'),d={name:"modern-nlp/llm.md"};function l(i,t,r,h,p,o){return n(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="第二十三章-大语言模型原理" tabindex="-1">第二十三章：大语言模型原理 <a class="header-anchor" href="#第二十三章-大语言模型原理" aria-label="Permalink to &quot;第二十三章：大语言模型原理&quot;">​</a></h1><p><strong>大语言模型</strong>（Large Language Model，LLM）是 NLP 发展到今天最重要的技术方向。本章讲解 LLM 的核心原理、规模定律和涌现能力。</p><hr><h2 id="什么是大语言模型" tabindex="-1">什么是大语言模型？ <a class="header-anchor" href="#什么是大语言模型" aria-label="Permalink to &quot;什么是大语言模型？&quot;">​</a></h2><p>大语言模型是指参数量达到数十亿甚至数千亿的语言模型，它们通过在海量文本数据上训练，展现出了强大的语言理解和生成能力。</p><h3 id="核心特征" tabindex="-1">核心特征 <a class="header-anchor" href="#核心特征" aria-label="Permalink to &quot;核心特征&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特征</th><th>说明</th></tr></thead><tbody><tr><td>大规模参数</td><td>通常 1B+ 参数</td></tr><tr><td>海量训练数据</td><td>数万亿 token 的文本</td></tr><tr><td>涌现能力</td><td>小模型不具备、大模型突然出现的能力</td></tr><tr><td>通用性</td><td>一个模型可以完成多种任务</td></tr></tbody></table><hr><h2 id="规模定律-scaling-laws" tabindex="-1">规模定律（Scaling Laws） <a class="header-anchor" href="#规模定律-scaling-laws" aria-label="Permalink to &quot;规模定律（Scaling Laws）&quot;">​</a></h2><h3 id="kaplan-scaling-laws" tabindex="-1">Kaplan Scaling Laws <a class="header-anchor" href="#kaplan-scaling-laws" aria-label="Permalink to &quot;Kaplan Scaling Laws&quot;">​</a></h3><p>OpenAI 的 Kaplan 等人（2020）发现了语言模型性能的<strong>幂律关系</strong>：</p><p>$$L(N) \\propto N^{-\\alpha_N}$$</p><p>$$L(D) \\propto D^{-\\alpha_D}$$</p><p>$$L(C) \\propto C^{-\\alpha_C}$$</p><p>其中：</p><ul><li>$L$ 是损失（loss）</li><li>$N$ 是模型参数量</li><li>$D$ 是训练数据量（token 数）</li><li>$C$ 是计算量（FLOPs）</li><li>$\\alpha$ 是幂律指数</li></ul><p><strong>核心发现</strong>：</p><ol><li>模型性能随参数量、数据量、计算量的增加而<strong>持续提升</strong></li><li>三者之间存在<strong>最优分配比例</strong></li></ol><h3 id="chinchilla-scaling-laws" tabindex="-1">Chinchilla Scaling Laws <a class="header-anchor" href="#chinchilla-scaling-laws" aria-label="Permalink to &quot;Chinchilla Scaling Laws&quot;">​</a></h3><p>DeepMind 的 Hoffmann 等人（2022）提出了修正的规模定律：</p><p><strong>核心发现</strong>：模型参数量和训练数据量应该<strong>同比例增长</strong>。</p><table tabindex="0"><thead><tr><th>模型</th><th>参数量</th><th>训练 token 数</th><th>比例</th></tr></thead><tbody><tr><td>Gopher</td><td>280B</td><td>300B</td><td>1:1</td></tr><tr><td>Chinchilla</td><td>70B</td><td>1.4T</td><td>1:20</td></tr><tr><td>LLaMA</td><td>7B</td><td>1T</td><td>1:143</td></tr></tbody></table><p>Chinchilla 用更少的参数、更多的数据，达到了更好的效果。</p><hr><h2 id="涌现能力-emergent-abilities" tabindex="-1">涌现能力（Emergent Abilities） <a class="header-anchor" href="#涌现能力-emergent-abilities" aria-label="Permalink to &quot;涌现能力（Emergent Abilities）&quot;">​</a></h2><h3 id="什么是涌现能力" tabindex="-1">什么是涌现能力？ <a class="header-anchor" href="#什么是涌现能力" aria-label="Permalink to &quot;什么是涌现能力？&quot;">​</a></h3><p>涌现能力是指<strong>只在模型规模超过某个阈值时才突然出现</strong>的能力。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型参数:  1B    10B    100B   200B</span></span>
<span class="line"><span>算术推理:  差    差     突然好  很好  ← 涌现！</span></span>
<span class="line"><span>代码生成:  不行  勉强   突然行  很行  ← 涌现！</span></span></code></pre></div><h3 id="常见的涌现能力" tabindex="-1">常见的涌现能力 <a class="header-anchor" href="#常见的涌现能力" aria-label="Permalink to &quot;常见的涌现能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>少样本学习</td><td>通过几个示例学会新任务</td></tr><tr><td>思维链推理</td><td>逐步推理解决复杂问题</td></tr><tr><td>代码生成</td><td>生成可执行的代码</td></tr><tr><td>指令遵循</td><td>理解并执行复杂指令</td></tr><tr><td>多语言能力</td><td>在未显式训练的语言上表现良好</td></tr></tbody></table><hr><h2 id="思维链-chain-of-thought" tabindex="-1">思维链（Chain of Thought） <a class="header-anchor" href="#思维链-chain-of-thought" aria-label="Permalink to &quot;思维链（Chain of Thought）&quot;">​</a></h2><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><p>思维链是一种<strong>提示技术</strong>，通过让模型&quot;一步一步思考&quot;来提升推理能力。</p><h3 id="标准提示-vs-思维链提示" tabindex="-1">标准提示 vs 思维链提示 <a class="header-anchor" href="#标准提示-vs-思维链提示" aria-label="Permalink to &quot;标准提示 vs 思维链提示&quot;">​</a></h3><p><strong>标准提示</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问：小明有 5 个苹果，给了小红 2 个，又买了 3 个，现在有几个？</span></span>
<span class="line"><span>答：6</span></span></code></pre></div><p><strong>思维链提示</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问：小明有 5 个苹果，给了小红 2 个，又买了 3 个，现在有几个？</span></span>
<span class="line"><span>答：让我一步一步思考。</span></span>
<span class="line"><span>1. 小明开始有 5 个苹果</span></span>
<span class="line"><span>2. 给了小红 2 个：5 - 2 = 3 个</span></span>
<span class="line"><span>3. 又买了 3 个：3 + 3 = 6 个</span></span>
<span class="line"><span>所以现在有 6 个苹果。</span></span></code></pre></div><h3 id="为什么思维链有效" tabindex="-1">为什么思维链有效？ <a class="header-anchor" href="#为什么思维链有效" aria-label="Permalink to &quot;为什么思维链有效？&quot;">​</a></h3><ol><li><strong>分解复杂问题</strong>：将复杂推理分解为简单步骤</li><li><strong>减少错误传播</strong>：每一步都可以验证</li><li><strong>激活知识</strong>：逐步推理帮助模型激活相关知识</li></ol><hr><h2 id="主流大语言模型" tabindex="-1">主流大语言模型 <a class="header-anchor" href="#主流大语言模型" aria-label="Permalink to &quot;主流大语言模型&quot;">​</a></h2><h3 id="闭源模型" tabindex="-1">闭源模型 <a class="header-anchor" href="#闭源模型" aria-label="Permalink to &quot;闭源模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>公司</th><th>参数量</th><th>特点</th></tr></thead><tbody><tr><td>GPT-4</td><td>OpenAI</td><td>未公开</td><td>多模态、最强推理</td></tr><tr><td>GPT-4o</td><td>OpenAI</td><td>未公开</td><td>多模态、更快</td></tr><tr><td>Claude 3.5</td><td>Anthropic</td><td>未公开</td><td>长上下文、安全</td></tr><tr><td>Gemini</td><td>Google</td><td>未公开</td><td>多模态</td></tr></tbody></table><h3 id="开源模型" tabindex="-1">开源模型 <a class="header-anchor" href="#开源模型" aria-label="Permalink to &quot;开源模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>公司</th><th>参数量</th><th>特点</th></tr></thead><tbody><tr><td>LLaMA 2</td><td>Meta</td><td>7B-70B</td><td>最早的高质量开源模型</td></tr><tr><td>LLaMA 3</td><td>Meta</td><td>8B-405B</td><td>性能接近 GPT-4</td></tr><tr><td>Qwen</td><td>阿里</td><td>0.5B-72B</td><td>中文优化</td></tr><tr><td>DeepSeek</td><td>DeepSeek</td><td>7B-67B</td><td>性价比高</td></tr><tr><td>Mistral</td><td>Mistral</td><td>7B-8x22B</td><td>高效架构</td></tr></tbody></table><hr><h2 id="llm-的训练流程" tabindex="-1">LLM 的训练流程 <a class="header-anchor" href="#llm-的训练流程" aria-label="Permalink to &quot;LLM 的训练流程&quot;">​</a></h2><h3 id="三阶段训练" tabindex="-1">三阶段训练 <a class="header-anchor" href="#三阶段训练" aria-label="Permalink to &quot;三阶段训练&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段1：预训练（Pre-training）</span></span>
<span class="line"><span>  数据：海量无标注文本（数万亿 token）</span></span>
<span class="line"><span>  目标：自回归语言模型（预测下一个词）</span></span>
<span class="line"><span>  结果：获得通用的语言能力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段2：监督微调（Supervised Fine-Tuning, SFT）</span></span>
<span class="line"><span>  数据：高质量的指令-回复对</span></span>
<span class="line"><span>  目标：学习遵循指令</span></span>
<span class="line"><span>  结果：能够理解并执行指令</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段3：人类对齐（Alignment）</span></span>
<span class="line"><span>  方法：RLHF 或 DPO</span></span>
<span class="line"><span>  目标：让输出符合人类偏好</span></span>
<span class="line"><span>  结果：更安全、更有帮助</span></span></code></pre></div><hr><h2 id="llm-的推理优化" tabindex="-1">LLM 的推理优化 <a class="header-anchor" href="#llm-的推理优化" aria-label="Permalink to &quot;LLM 的推理优化&quot;">​</a></h2><h3 id="kv-cache" tabindex="-1">KV Cache <a class="header-anchor" href="#kv-cache" aria-label="Permalink to &quot;KV Cache&quot;">​</a></h3><p>在自回归生成时，每个新 token 需要计算与所有之前 token 的注意力。KV Cache 缓存之前计算的 Key 和 Value，避免重复计算。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>无 KV Cache：</span></span>
<span class="line"><span>  生成 token 5 时：计算 Q5×[K1,K2,K3,K4] → O(n²)</span></span>
<span class="line"><span>  生成 token 6 时：计算 Q6×[K1,K2,K3,K4,K5] → O(n²)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>有 KV Cache：</span></span>
<span class="line"><span>  生成 token 5 时：计算 Q5×[K1,K2,K3,K4]，缓存 K5, V5</span></span>
<span class="line"><span>  生成 token 6 时：计算 Q6×[K5]（只计算新部分）→ O(n)</span></span></code></pre></div><h3 id="量化" tabindex="-1">量化 <a class="header-anchor" href="#量化" aria-label="Permalink to &quot;量化&quot;">​</a></h3><p>将模型权重从 FP32 压缩到更低精度：</p><table tabindex="0"><thead><tr><th>精度</th><th>大小（7B 模型）</th><th>性能损失</th></tr></thead><tbody><tr><td>FP32</td><td>28GB</td><td>无</td></tr><tr><td>FP16</td><td>14GB</td><td>几乎无</td></tr><tr><td>INT8</td><td>7GB</td><td>很小</td></tr><tr><td>INT4</td><td>3.5GB</td><td>较小</td></tr></tbody></table><h3 id="推测解码-speculative-decoding" tabindex="-1">推测解码（Speculative Decoding） <a class="header-anchor" href="#推测解码-speculative-decoding" aria-label="Permalink to &quot;推测解码（Speculative Decoding）&quot;">​</a></h3><p>使用小型&quot;草稿&quot;模型快速生成多个候选 token，然后用大型模型验证。</p><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td>规模定律</td><td>性能随参数/数据/计算量的增加而提升</td></tr><tr><td>涌现能力</td><td>大规模时突然出现的能力</td></tr><tr><td>思维链</td><td>逐步推理提升复杂问题的解决能力</td></tr><tr><td>三阶段训练</td><td>预训练 → SFT → 对齐</td></tr><tr><td>KV Cache</td><td>缓存注意力计算结果，加速推理</td></tr></tbody></table><p>大语言模型代表了 NLP 的当前最前沿。理解其原理，有助于我们更好地使用和开发这些模型。</p>`,65)])])}const u=a(d,[["render",l]]);export{b as __pageData,u as default};
